import React, { useState } from "react";

function Upload({ onNext, onBack }) {
  const [name, setName] = useState("");
  const [dateTime, setDateTime] = useState("");
  const [screenshotFile, setScreenshotFile] = useState(null);
  const [previewUrl, setPreviewUrl] = useState("");

  const handleFileChange = (event) => {
    const file = event.target.files?.[0];
    if (!file) return;
    setScreenshotFile(file);
    setPreviewUrl(URL.createObjectURL(file));
  };

  const handleNext = () => {
    // Simulated screenshot extraction if user uploads an image.
    const simulatedName = "Football Training";
    const simulatedDateTime = new Date(Date.now() + 86400000)
      .toISOString()
      .slice(0, 16);

    if (!screenshotFile && (!name || !dateTime)) {
      alert("Upload a screenshot OR enter both activity name and date/time.");
      return;
    }

    onNext({
      source: screenshotFile ? "screenshot" : "manual",
      name: screenshotFile ? simulatedName : name,
      dateTime: screenshotFile ? simulatedDateTime : dateTime,
      screenshotName: screenshotFile ? screenshotFile.name : "",
      screenshotPreviewUrl: screenshotFile ? previewUrl : ""
    });
  };

  const labelStyle = { display: "block", marginBottom: "0.35rem", fontWeight: 600 };
  const inputStyle = {
    width: "100%",
    padding: "0.65rem",
    borderRadius: 8,
    border: "1px solid #cbd5e1",
    marginBottom: "0.9rem"
  };
  const buttonStyle = {
    border: "none",
    padding: "0.7rem 1.1rem",
    borderRadius: 8,
    fontWeight: 600,
    cursor: "pointer",
    marginRight: "0.75rem"
  };

  return (
    <div>
      <h2 style={{ marginTop: 0 }}>Upload Screen</h2>
      <p style={{ color: "#475569", marginTop: 0 }}>
        Upload an activity screenshot or type the activity details manually.
      </p>

      <label style={labelStyle}>Upload Screenshot</label>
      <input type="file" accept="image/*" onChange={handleFileChange} style={inputStyle} />

      {previewUrl && (
        <div style={{ marginBottom: "1rem" }}>
          <img
            src={previewUrl}
            alt="Uploaded activity screenshot"
            style={{ width: "100%", maxWidth: 360, borderRadius: 10, border: "1px solid #cbd5e1" }}
          />
        </div>
      )}

      <p style={{ margin: "1rem 0 0.5rem", fontWeight: 600 }}>OR enter manually</p>
      <label style={labelStyle}>Activity Name</label>
      <input
        type="text"
        value={name}
        onChange={(e) => setName(e.target.value)}
        placeholder="e.g. Football Training"
        style={inputStyle}
      />

      <label style={labelStyle}>Date and Time</label>
      <input
        type="datetime-local"
        value={dateTime}
        onChange={(e) => setDateTime(e.target.value)}
        style={inputStyle}
      />

      <button onClick={handleNext} style={{ ...buttonStyle, background: "#2563eb", color: "#fff" }}>
        Next
      </button>
      <button onClick={onBack} style={{ ...buttonStyle, background: "#e2e8f0", color: "#0f172a" }}>
        Back
      </button>
    </div>
  );
}

export default Upload;
